      "readingAid": "g",
      "symbol": "ㄱ"
    },
    {
      "audioText": "나",
      "forms": [],
      "pronunciation": "Suena igual que la 'n' en 'nada'.",
      "readingAid": "n",
      "symbol": "ㄴ"
    },
    {
      "audioText": "다",
      "forms": [],
